import requests
import urllib.parse
from typing import Optional, Dict, Any
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def fetch_and_display_url_content(url: str, headers: Optional[Dict[str, str]] = None, timeout: int = 30) -> Optional[str]:
    """
    Fetches and displays content from a URL with security considerations.
    
    Args:
        url (str): The URL to fetch content from
        headers (Optional[Dict[str, str]]): Optional headers for the request
        timeout (int): Request timeout in seconds
        
    Returns:
        Optional[str]: The content fetched from the URL or None if failed
    """
    try:
        # Validate URL format
        parsed_url = urllib.parse.urlparse(url)
        if not all([parsed_url.scheme, parsed_url.netloc]):
            logger.error(f"Invalid URL format: {url}")
            return None
            
        # Security: Only allow HTTP/HTTPS schemes
        if parsed_url.scheme not in ['http', 'https']:
            logger.error(f"Unsupported URL scheme: {parsed_url.scheme}")
            return None
            
        # Security: Validate domain is not localhost or private IP
        if is_private_ip(parsed_url.netloc):
            logger.error(f"Access to private IP not allowed: {parsed_url.netloc}")
            return None
            
        # Set default headers to prevent security issues
        default_headers = {
            'User-Agent': 'AWS-Integration-Service/1.0',
            'Accept': '*/*',
            'Accept-Encoding': 'gzip, deflate',
            'Connection': 'close'
        }
        
        if headers:
            default_headers.update(headers)
            
        # Make the request with timeout
        response = requests.get(
            url,
            headers=default_headers,
            timeout=timeout,
            allow_redirects=True
        )
        
        # Check response status
        response.raise_for_status()
        
        # Log successful request
        logger.info(f"Successfully fetched content from {url}")
        
        return response.text
        
    except requests.exceptions.RequestException as e:
        logger.error(f"Request failed for URL {url}: {str(e)}")
        return None
    except Exception as e:
        logger.error(f"Unexpected error fetching URL {url}: {str(e)}")
        return None

def is_private_ip(hostname: str) -> bool:
    """
    Check if hostname resolves to a private IP address.
    
    Args:
        hostname (str): Hostname to check
        
    Returns:
        bool: True if private IP, False otherwise
    """
    try:
        import socket
        ip = socket.gethostbyname(hostname)
        # Check for private IP ranges
        private_ranges = [
            '10.',
            '172.16.',
            '172.17.',
            '172.18.',
            '172.19.',
            '172.20.',
            '172.21.',
            '172.22.',
            '172.23.',
            '172.24.',
            '172.25.',
            '172.26.',
            '172.27.',
            '172.28.',
            '172.29.',
            '172.30.',
            '172.31.',
            '192.168.'
        ]
        return any(ip.startswith(private_range) for private_range in private_ranges)
    except:
        return False

def process_webhook(url: str, payload: Dict[str, Any]) -> Optional[str]:
    """
    Process webhook by fetching content from URL with payload.
    
    Args:
        url (str): The webhook URL
        payload (Dict[str, Any]): The payload to send
        
    Returns:
        Optional[str]: The content fetched or None if failed
    """
    try:
        # Validate URL
        parsed_url = urllib.parse.urlparse(url)
        if not all([parsed_url.scheme, parsed_url.netloc]):
            logger.error(f"Invalid webhook URL: {url}")
            return None
            
        # Make POST request with payload
        response = requests.post(
            url,
            json=payload,
            timeout=30,
            headers={'Content-Type': 'application/json'}
        )
        response.raise_for_status()
        logger.info(f"Webhook processed successfully: {url}")
        return response.text
        
    except requests.exceptions.RequestException as e:
        logger.error(f"Webhook request failed for URL {url}: {str(e)}")
        return None
    except Exception as e:
        logger.error(f"Unexpected error processing webhook {url}: {str(e)}")
        return None